            //
            aOrbiterH = (aOrbiterH + aOrbiterJ) + 7008985178526543258U;
            aOrbiterI = (aOrbiterI ^ aOrbiterH) ^ 13576796403863120356U;
            aOrbiterI = RotL64((aOrbiterI * 13745839827679114077U), 53U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 5769784656937900699U;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterK) ^ 14075925808204936705U) ^ aOrbiterUpdateSaltB[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 5844894088757604713U), 43U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterH) + 17818667502858010896U;
            aOrbiterD = ((aOrbiterD ^ aOrbiterA) ^ 16016922065572683130U) ^ aNonceWordM;
            aOrbiterD = RotL64((aOrbiterD * 7525645833898085373U), 41U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterF) + 1582458237855075977U;
