            aOrbiterA = RotL64((aOrbiterA * 4682098083538482849U), 5U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterK) + 14846954923718136337U) + aOrbiterUpdateSaltC[((aIndex + 8U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterE) ^ 522207783972623813U;
