            aIngress = aIngress + (RotL64(aOrbiterF, 29U) ^ aOrbiterK);
            aIngress = aIngress + RotL64(aOrbiterD, 51U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererH = aWandererH + ((RotL64(aIngress, 57U) + RotL64(aOrbiterK, 13U)) + aOrbiterD);
            aWandererK = aWandererK ^ (((RotL64(aScatter, 11U) + RotL64(aOrbiterC, 58U)) + aOrbiterE) + aWandererUpdateSaltD[(((31U - aIndex) + 21U)) & S_SALT1]);
            aWandererG = aWandererG + ((RotL64(aCross, 39U) + aOrbiterA) + RotL64(aOrbiterJ, 29U));
